@GrpcService
class ProfileGrpcService(
    private val profileService: ProfileDomainService,
) : ProfileServiceGrpc.ProfileServiceImplBase() {

    override fun getProfile(
        request: GetProfileRequest,
        responseObserver: StreamObserver<GetProfileResponse>,
    ) {
        val profile = profileService.getProfile(request.requesterUserId, request.targetUserId)
        responseObserver.onNext(
            GetProfileResponse.newBuilder().setProfile(profile.toProto()).build()
        )
        responseObserver.onCompleted()
    }

    override fun updateProfile(
        request: UpdateProfileRequest,
        responseObserver: StreamObserver<UpdateProfileResponse>,
    ) {
        val updatedProfile = profileService.updateProfile(request)
        responseObserver.onNext(
            UpdateProfileResponse.newBuilder().setProfile(updatedProfile.toProto()).build()
        )
        responseObserver.onCompleted()
    }
}
